import React, { Component } from 'react';

class Mangacontainer extends Component {
    render() {
        return (
         <div className="manga-info">
            <div className="children-manga">
              <img src="https://f01.mrcdn.info/file/mrportal/h/b/l/8/jg.eNHZG-Su.png" alt=" " />
              <a href>Manga 1</a>
            </div>
            <a href>Chapter 1</a>
            <p>1 hour<br />ago</p>    
          </div>
        );
    }
}

export default Mangacontainer;
